  INSERT INTO feedback_entries (athlete_id, exercise_name, fehlerbild, handlungsanweisung, context, given_by, feedback_type, dartfish_url, helpful, r_technik, r_ausfuehrung, r_fortschritt, r_programm, r_wettkampf) VALUES
    (md5('fbath:Philipp Rapp')::uuid, 'Drehsprung', '1. Schulter beim Weitermachen zu weit hinten 2.auf Video gesehen das Po zu weit unten beim Weitermachen, daher auch Schulter zu weit hinten.', 'Anweisung: po weiter oben lassen beim drüber gehen. Aber wie? 2. Schulter weiter vorne lassen beim drüber gehen. Aber wie ? 3. Über eine Bank springen. Dadurch Gefühl geholt wie Schulter ansteuern kann, damit sie weiter vorne bleibt. Somit ist der po weiter oben. Und Lenker läuft auch nichtmehr mit sondern bleibt eher stehen und Schulter dreht mit.', 'Heimtraining', 'Heimtrainer', 'Video - ausführliche Analyse (Video- Korrektur - Video 2)', 'https://dartfi.sh/R3k3eFNDowf', 5, 4, 3, 3, 4, 2),
    (md5('fbath:Philipp Rapp')::uuid, 'Kehrstandsteiger Drehung', 'Oberkörper zu weit innen (da ich mit links vorne, rechts hinten verdreht bin.', 'Linke Schulter zurück/rechte Schulter vor (Gegenteil von dem wie ich’s bisher fahr)', 'Heimtraining', 'Heimtrainer', 'verbale Korrektur nach der Übung', '', 5, 3, 4, 3, 4, 4),
    (md5('fbath:Philipp Rapp')::uuid, 'Drehsprung', 'Weiterspringen: Schulter zu weit hinten. Zu großer Abstand zwischen Arm und Hüfte und Lenker dreht zu langsam/ Oberkörper ist schneller als Lenker', 'Drüber stützen und Lenker maximal schnell drehen.', 'Heimtraining', 'Heimtrainer', 'Video - ausführliche Analyse (Video- Korrektur - Video 2)', 'https://dartfi.sh/GwCoj0Ssnq5', 4, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'Kehrsteuerrohrsteigerdrehung', 'Haltung in der Drehung, nicht in der Achse in der Drehung, Folge: Schwung wird weggenommen', 'Becken früher nach vorne bringen, Schultern bzw. ganzen Körper aufrichten und nach oben nehmen', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'verbale Korrektur nach der Übung', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Philipp Rapp')::uuid, 'Drehsprung', '(AUFDREHEN) Beim drüber springen Dreh ich mit der linken Schulter nach hinten auf und geh somit mit der ganzen Schulter nach hinten', '(EINDREHEN) Beim drüber springen eindrehen nicht auf', 'Heimtraining', 'Heimtrainer', 'Video - ausführliche Analyse (Video- Korrektur - Video 2)', '', 4, 4, 4, 4, 4, 4),
    (md5('fbath:Philipp Rapp')::uuid, 'Drehsprung', 'Po', 'Knie eng an den Körper (dann Dreh ich automatisch ein) + versuchen Bein am Körper zu lassen, damit Po oben bleibt', 'Heimtraining', 'Heimtrainer', 'Video - ausführliche Analyse (Video- Korrektur - Video 2)', '', 4, 4, 4, 4, 4, 4),
    (md5('fbath:Simon Halter')::uuid, 'Rückwärtsserie', 'Körper-Rad-Verbindung zu instabil und langsam', 'Mehr Rückenspannung, Arm rechts weiter vor, halber Meter größer fahren und Tritt ein wenig schneller', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'verbale Korrektur nach der Übung', '', NULL, 3, 3, 2, 4, 3),
    (rubath, 'Seitvorhebehalte rw.', 'Zackige Lenk Bewegungen unsicher  zu weit über dem Sattel geschoben', 'Mehr Druck auf den Lenker geben, nicht ganz so weit über den Sattel schieben', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'verbale Korrektur nach der Übung', '', NULL, 2, 2, 2, 3, 2),
    (rubath, 'Maute Sprung', 'Hart gelandet und nicht gestanden', 'Weicher springen und landen mehr setzen', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'verbale Korrektur nach der Übung', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Sandra Öhler')::uuid, 'Sprung', 'Zu weit in die Knie und abspringen', 'Nur über Fußspitzen abrollen, Knie auf einer Höhe lassen, gegen Brett bewegen', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'verbale Korrektur nach der Übung', '', 4, 2, 2, 2, 1, 1),
    (md5('fbath:Hannah Reichle')::uuid, 'Sattellenkerhandstand', 'Schub Becken nach oben und aufrollen Rücken fehlt.', 'Beim lösen der Beine nicht die Bein zu Körper herziehen sondern nur über Schulter und Rücken aktiv werden', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'Video - ausführliche Analyse (Video- Korrektur - Video 2)', 'https://dartfi.sh/lQOJaTf43be', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'Sattellenkerstand rw', 'oft nach außen kippen, lenken nicht fein genug', 'Knie mehr durchstrecken, Druck mehr auf den Lenker verlagern, mit Halten oben schieben', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'verbale Korrektur nach der Übung', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Reichle')::uuid, 'Drehsprung', 'Schwingt zu flach, Lenker läuft mit', 'Mehr Impuls beim Rausspringen und Schultern vor. Beine fast zusammen lassen beim Weiterspringen (Video wurde nicht Hochgeladen versuche es nachzureichen)', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'Video - ausführliche Analyse (Video- Korrektur - Video 2)', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Sandra Öhler')::uuid, 'Übergang Kehrlenkersitzsteiger', 'Stehe nach vorne auf, Po geht zuerst Richtung Lenker', 'Gefühl: Brustkorb nach oben hinten bewegen und Bauch anspannen um Becken vorne zu lassen', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'Video - einfache Analyse', '', 5, 3, 3, 3, 2, 2),
    (md5('fbath:Maximilian Keller')::uuid, 'Kehrstandsteiger', 'Oberkörper beim rausgehen verdreht, rechte Schulter geht nach vorne', 'noch oben rausgehen und aufrecht bleiben', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'verbale Korrektur nach der Übung', '', NULL, 3, 3, 4, 3, 2),
    (md5('fbath:Hannah Reichle')::uuid, 'Sattelenkerhandstand', 'Beim Hochdrücken: In den Moment, wo ich meine Füße löse geht mein Bechen eher nach unten und ich drücke meine Oberschenkel an meinen Oberkörper (mach mich zu eng)', 'Füße leicht machen und beim Lösen die Oberschenkel nicht an den Oberkörper drücken, Beine früher öffnen', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'Video - einfache Analyse', 'https://dartfi.sh/lQOJaTf43be', 4, 2, 1, 1, 1, 1),
