    (md5('fbath:Hannah Schneider')::uuid, 'Kehrsteuerrohrsteiger Drehung', 'Position in der Drehung wird nicht gehalten', 'gleichmäßigen Druck auf beiden Pedalen haben und Brustbein in der Drehung nach oben ziehen', 'C-Kader', 'Heimtrainer', 'verbale Korrektur nach der Übung', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Reichle')::uuid, 'Drehsprung', 'Selbst wenn ich länger warte bevor ich über den Sattel in die zweite Rund starte, mache ich meine Beine soweit auf, dass mein Oberschenkel wieder im Weg ist um den Lenker durchzudrehen', 'Versuchen die Beine nur so viel zu öffnen, dass der Rahmen dazwischenpasst', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'verbale Korrektur nach der Übung', '', 5, 3, 2, 2, 2, 2),
    (md5('fbath:Hannah Schneider')::uuid, 'Lenkerstanddrehung', 'Auslösen nicht effektiv, Lenkerbewegung beim Vordrehen', 'Verdrehen langsam beschleunigt, weiter und mit mehr Armspannung', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'Video - einfache Analyse', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Reichle')::uuid, 'Drehsprung', 'Ich warte nicht bis ich an der Seite bin (mit dem Becken an der Hand vorbei bin) und ziehe damit zu früh meine Beine an', 'Nicht durchhängen, damit ich mehr Platz habe und damit länger warten kann, bewusst diese „Ruhephase“ spüren', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'Video - einfache Analyse', '', 5, 3, 2, 2, 2, 2),
    (md5('fbath:Linus Weber')::uuid, 'Drehsprung', 'Schulter zu weit hinten --> Lenker zu langsam, nicht sauber schwingen und zu weit über rechter Schulter', 'Schulter weiter vor', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'verbale Korrektur nach der Übung', '', 5, 3, 3, 4, 4, 4),
