    (md5('fbath:Linus Weber')::uuid, 'Kehrreitsitzsteiger Drehung', 'Körper-Rad-Winkel zu groß dadurch Kontrolle schwierig, zu wenig Schräglage deshalb verdrehen Oberkörper', 'nach dem Hochgehen direkt Becken besser vor Körper-Rad-Winkel kleiner und richtige Schräglage das Tritt Drehung ankurbeln kann.', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'Video - einfache Analyse', '', NULL, 4, 4, NULL, 4, 4),
