    (md5('fbath:Jonas Beiter')::uuid, 'Drehsprung', 'Lenker läuft zu früh mit beim Weiterspringen', 'Schulter weiter vor (dadurch höheres ankommen am Arm, mehr Eindrehen rechte Schulter und um Arm kurz machen', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'Video - ausführliche Analyse (Video- Korrektur - Video 2)', 'https://dartfi.sh/ZCdv0nfuhuc', NULL, NULL, NULL, NULL, NULL, NULL),
