    (md5('fbath:Hannah Schneider')::uuid, 'Lenkerstanddrehung', 'Auslösen erste halbe uneffektiv und nicht in Körperachse', 'Vordrhen etwas besser langsam beschleinigen, Mehr Spannung Schultern damit Arme nicht schlagen, beim Auslösen mehr Gesamtkörperspannung aufbauen und Becken mit drehen (Insbesondere rechte Beckenseite nach vorne)', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'Video - ausführliche Analyse (Video- Korrektur - Video 2)', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (rubath, 'Rückwärtsserie', 'Tritt unrund -> wird es langsamer', 'Weniger mit Kraft runter treten dadurch automatisch mehr ziehen. Außerdem mehr Druck auf die rechte Po Backe -> Mehr Hüftknick und Brust raus', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'verbale Korrektur nach der Übung', '', 4, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'Übergang Kehrlenkersitzsteiger Kehrsteuerrohrsteiger', 'Kommt zu spät am linken Pedal an.', 'Linker Fuß früher lösen, Bein schneller über den Lenker nehmen, Oberkörper senkrecht', 'Heimtraining', 'Lehrgangsleiter', 'Video - einfache Analyse', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Charlotte Bantle')::uuid, 'Drehsprung', 'Körper hängt direkt auf dem rechten Arm', 'Lenker stehen lassen und nach außen-oben abdrücken, erst dann Lenker schneller drehen', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'Video - ausführliche Analyse (Video- Korrektur - Video 2)', 'https://dartfi.sh/5kzD0870We1', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'Lenkerhandstand', 'Winkelt die Beine maximal an und verblockt sich. Dadurch aufrollen Rücken schlechter', 'Beine bleiben gestreckt und werden nur gespreizt. Schub über Schulter nach oben dann Rücken aufrollen.', 'Heimtraining', 'Lehrgangsleiter', 'Video - einfache Analyse', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Reichle')::uuid, 'Drehsprung', 'Schwingen mit zu viel seitlicher Tendenz (nicht oval), Lenker läuft zu früh mit und Energie geht verloren, Körper beim zweiten zu tief', 'linkes Bein geführter zu rechten Schwingen lassen, beim weiterspringen Beine mehr geschlossen lassen und um den Arm gehen, aktives Stützen beim 2.', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'Video - ausführliche Analyse (Video- Korrektur - Video 2)', 'https://dartfi.sh/oUXekeXoszh', NULL, NULL, NULL, NULL, NULL, NULL),
    (rubath, 'Drehsprung', 'Querschwingen vor dem Rad', 'linkes Bein nicht so früh und aktiv zum rechten bein sondern verzögert ranschwingen lassen, Schulter weiter vor und loslassen also passiv schwingen lassen und nicht das Rad zum Körper herziehen, beim weitersppringen Beine mehr geschlossen lassen', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'Video - ausführliche Analyse (Video- Korrektur - Video 2)', 'https://dartfi.sh/SuADjb9Hzq0', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Jonas Beiter')::uuid, 'Drehsprung', 'Lenker läuft quer', 'Länger warten und beim kurz machen der eine rechte Schulter nach vorne eindrehen und um den Arm gehen um den Lenker etwas länger stehen zu lassen und rechtzeitg dann den Lenker schnell zu machen. Grundsätzlich Schulter besser vorne lassen', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'Video - ausführliche Analyse (Video- Korrektur - Video 2)', 'https://dartfi.sh/0IpURZEtX9g', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Lara Füller')::uuid, 'Drehsprung', 'Lenker läuft zu früh mit', 'rechte Schulter nach vorne eindrehen und mehr das Bein und des becken um den Arm nehmen sodass der Lenker länger stehen bleibt und dann rechtzeit schnell wird.', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'Video - ausführliche Analyse (Video- Korrektur - Video 2)', 'https://dartfi.sh/CBJf3D4qBYk', NULL, NULL, NULL, NULL, NULL, NULL),
    (rubath, 'Maute Sprung', 'Zu viel Druck auf dem Sattel Kranz beim Aufgang. Dadurch zu wenig Druck auf Zehen -> Sattel stand nicht sauber', 'Vorne bleiben beim hochgehen und Druck auf Zehen spitzen.', 'Lehrgang Albstadt', 'Heimtrainer', 'verbale Korrektur nach der Übung', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'ÜG Kehrlenkersitz Kehrsteuerrohrsteiger', 'Zeitpunkt vom Lösen des Beines zu spät', 'Bein früher lösen', 'Lehrgang Albstadt', 'anderer Trainer', 'verbale Korrektur nach der Übung', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Maximilian Keller')::uuid, 'Übergang Kehrlenkersitzsteiger Kehrsteuerrohrsteiger', 'kommt zu spät mit dam linken Fuß aufs Pedal. Pedal läuft schon entgegen.', 'Beginn etwas weicher (wie bei einem Wechseltritt), früher Lenker rechst hochziehen, Oberkörper senkrecht/aufrecht lassen', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'Video - einfache Analyse', 'https://dartfi.sh/JMEyojZvHa6', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Simon Halter')::uuid, 'Drehsprung', 'Schwingt zu tief und mit falscher Richtung an Arm', 'Flacher rausspringen und Schulter weiter vor, Beine zusammenlassen zum weiterspringen', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'Video - einfache Analyse', 'https://dartfi.sh/YKeeuvk6FPb', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Ferdinand Hirt')::uuid, 'Kehrsteuerrohrsteiger Standdrehung', 'läuft auseineander und zu wenig Schwung', 'Ferdinand Becken beim Vordrehen vorne lassen, nicht ganz soweit ausholen, Florian Abdruch früher mit Ferdinand', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'Video - einfache Analyse', 'https://dartfi.sh/lW5Higf7PM1', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Linus Weber')::uuid, 'Handstand', 'Schub aus Schulter fehlt', 'Start des Hochdrückens ist das sinkrecht nach oben schieben des Beckens', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'Video - einfache Analyse', 'https://dartfi.sh/NDlKchznGsi', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Maximilian Keller')::uuid, 'Ablassen Steuerrohrsteiger rw in Fronthang rw', 'kommt zu hart runter', 'Pedalstellung etwas später, Körper höher stützen', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'Video - einfache Analyse', 'https://dartfi.sh/7ID3JNMHy6e', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Linus Weber')::uuid, 'Handstand', 'Po bleibt zu tief', 'Schub über Schulter und öffnen Schulterwinkel Beginn hochdrücken', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'Video - einfache Analyse', 'https://dartfi.sh/crcu6Bm74Kh', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Maximilian Keller')::uuid, 'Ü. Kehrlenkersitz-Kehrsteuerrohrstg', 'Oberkörper, Ausweichen nach vorne', 'Position,', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'Video - ausführliche Analyse (Video- Korrektur - Video 2)', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Philipp Rapp')::uuid, 'Salto', 'Rad bleibt stehen und Lenker dreht sich stark nach rechts', 'Oberkörper senkrechter lassen für Radlauf, Drehen Lenker Ursache noch nicht erkannt', 'Heimtraining', 'Dieter Maute', 'Video - einfache Analyse', 'https://dartfi.sh/jCiaJp1roie    und    https://dartfi.sh/aSu1X5RIRvf', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Sandra Öhler')::uuid, 'Steuerrohrsteiger Drh.', 'Abspringen wenn’s zu schnell wird', 'Gerade Rücken, auf Radschräglage achten, bevor ich hochgehe noch mehr ankurbeln', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'verbale Korrektur während der Übung', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Sandra Öhler')::uuid, 'Übergang Kehrlenkersitzsteiger', 'Ich schiebe den Po direkt Richtung Lenker', 'Becken vor Schulter lassen, wenn rechtes Pedal vorne ist zählen, anfangsbewegung merken', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'verbale Korrektur nach der Übung', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Florian Hirt')::uuid, 'Standdrehung 2-fach', 'Pedalstellubng nach dem Auslösen, Abstand', 'Abstand zueinander beachten', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'Video - einfache Analyse', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Linus Weber')::uuid, 'Drehsprung', 'Gewicht zu weit auf rechtem Arm', 'Beim Rausspringen Lenker stehen lassen und mehr zur Seite raus, dann Lenker schnell drehen. Beim Weiterspringen linkes Bein früher in die Streckung losassen.', 'Lehrgang Albstadt', 'Dieter Maute', 'Video - einfache Analyse', 'https://dartfi.sh/pXT2WHwOM75', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Simon Halter')::uuid, 'Drehsprung', 'Lenker dreht zu langsam und Schwung geht aus', 'länger warten und beine zusammen lassen, mit linkem Becken Richtung rechtem Arm schwingen, dann rechte Scultereindrehen und Beine kurz machen um den rechte Arm herum, dann schnelles Lenkerdrehen, danach Schulter wirder vor', 'Lehrgang NK1', 'Dieter Maute', 'Video - einfache Analyse', 'https://dartfi.sh/NY3DW1DTy6e  und https://dartfi.sh/URiPQ4KqyE9', NULL, NULL, NULL, NULL, NULL, NULL),
    (rubath, 'Drehsprung', 'Schwingt zu flach, Drehgeschwindigkeit beim Weiterpringen zu gering', 'Beim rausspringen linkes Bein zur Seite und nicht zum anderen Bein nach unten heranführen, gleichzeitig Schultern deutlich weiter vor, danach länger warten und Bein im Knie beugen und um den Arm gehen, dabei rechte Schulter nach vorne einfdrehen (möglichst kurz und kompakt machen), beim Drehen des Lenkers müssen die Schutern besser über dem Lenker bleiben.', 'Heimtraining', 'Dieter Maute', 'Video - einfache Analyse', 'https://dartfi.sh/GfaCK7AX1qd', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'Steuerrohrsteiger Drehung', 'Drehung wird noch nicht klein und schnell genug', 'Rücken noch besser gerade spannen beim nach vorne gehen, über den Tritt noch eine wenig daruf setzen damit es schneller wird', 'Heimtraining', 'Dieter Maute', 'Video - einfache Analyse', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Sandra Öhler')::uuid, 'Drehsprung', 'Zu weit innen, zu langsam, zu weit nach vorne ab', 'Schneller anfahren, beim strecken, anderes Bein weiter nach außen, mehr stützen, mittig bleiben', 'Lehrgang Albstadt', 'anderer Trainer', 'verbale Korrektur nach der Übung', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Sandra Öhler')::uuid, 'Übergang Kehrlenkersitzsteiger', 'Mentale Blockade', 'Trainingsplan ausgearbeitet', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'verbale Korrektur nach der Übung', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Sandra Öhler')::uuid, 'Drehsprung', 'Becken an Armen, Lenker zu langsam gedreht, Knie nicht gestreckt, dadurch Po zu weit unten', '1. linker Fuß loslassen 2. rechtes Bein gestreckt lassen und über Schulter kommen 3. schnell Lenker drehen 4. Hüfte nach oben außen', 'Lehrgang Albstadt', 'Lehrgangsleiter und Matze', 'Video - einfache Analyse', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Reichle')::uuid, 'Sprung', 'kein Fehler', 'Gut einfach weiter machen', 'Heimtraining', 'Dieter Maute', 'Video - einfache Analyse', 'https://dartfi.sh/OutaUVX0E1a', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Reichle')::uuid, 'Sattellenkerhandstand', 'Körper-Oberschenkel-Winkel eng, Schulter bleibt vorne', 'Mehr auf Rücken aufrollen achten. Wenn Becken über die Schulter kommt muss sie Schulter weiter rausgeschoben werden und besser über die Hände. Dann Lenken (nicht drücken wie beim Lenkerhandstand) und  kontrolliert Beine schliesen', 'Heimtraining', 'Dieter Maute', 'Video - einfache Analyse', 'https://dartfi.sh/16oiXoICk4b', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Sandra Öhler')::uuid, 'Handstand', 'Becken zu früh aufgerollt, zu weit vorne geschlossen', 'Rücken aufrollen, am Kontrollpunkt langsam in Achse schließen', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'verbale Korrektur nach der Übung', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Sandra Öhler')::uuid, 'Drehsprung', 'Abdruck durch Knie, Bein nach hinten, schultervorlage geht weg', '1. Bein strecken 2. Abdruck durch Fuß 3. Lenker schnell drehen 4. Schultervorlage bis zum Ende -> wieder rein ziehen', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'Video - einfache Analyse', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'Sprung', 'Abdruck zu stark', 'leichteren Abdruck machen, nicht springen, Füße vorsetzen', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'Video - einfache Analyse', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Linus Weber')::uuid, 'Drehsprung', 'Kommt noch einwenig seitlich vom Schwung her an (Becken leicht aufgedreht), Lenker läuft tendenziell zu früh mit beim kurz machen zum Weiterspringen.', 'Linke Schulter noch etwas zu weit hinten. Beim Weiterspringen Bein noch kürzer um den Arm rum ohne dass Lenker mitläuft. Streckung des linken Beines nach dem drüber springen deutlich besser!', 'Heimtraining', 'Dieter Maute', 'Video - einfache Analyse', 'https://dartfi.sh/tXmIkyJY5nf', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Sandra Öhler')::uuid, 'Übergang Kehrlenkersitzsteiger', 'Kein Hochtreiben, nach dem Abstoppen weggesprungen', 'Automatismus vom Abstoppen danach Wahrnehmung auf das Hochtreiben (Lage im Raum, wohin geht mein OK), Po vor Schultern lassen, langsames Anfahren!!, auch im Programm mit Trainer', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'verbale Korrektur nach der Übung', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (rubath, 'Maute Sprung', 'Sattelstand kurz vor dem Sprung läuft nichtmehr so gut wie vorher', 'Kürzer anfahren und nicht auf einen Punkt festlegen wo ich springe sondern egal einspringen', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'verbale Korrektur nach der Übung', '', NULL, 3, NULL, NULL, NULL, NULL),
    (rubath, 'Drehspung', 'Bein geht senkrecht "Gestreckt" über Rahmen', 'Länger „warten“', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'Video - ausführliche Analyse (Video- Korrektur - Video 2)', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'Sprung', 'Abdruck etwas hart und nach oben', 'eweierer Abdruck (nur abrollen) dafür aktiver nach vorne setzten der Füße', 'Lehrgang Albstadt', 'Dieter Maute', 'Video - einfache Analyse', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'Handstand', 'Erste Phase ablösen Füße und Po Richtung Decke fehlt', 'Die erste Phase nochmals viel und intesiv mit ausgewählten Übungen trainieren', 'Lehrgang Albstadt', 'Dieter Maute', 'Video - einfache Analyse', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Maximilian Keller')::uuid, 'Drehsprung', 'Stoßt sich mit Fuß am Trainer ab und mit Fuß am Pedal hauptsächlich nach oben (Oberkörper/Po dananch zu hoch)', 'In Ausgangsposition Schulter rechts nach vorne eindreghen, dann maximal schnelles Drehen des Lenkers und Rausspringen ohne Abdruck am Trainer nach außen-vorne', 'Lehrgang Albstadt', 'Dieter Maute', 'Video - einfache Analyse', 'https://dartfi.sh/pJ4BmUhIoOd', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'Lenkerstanddrehung', 'Rad kippt nach Drehung/Körper nach innen weg', 'Beim Auslösen Rechten Arm nach hinten betonen, sodass der Oberkörper nicht über das innere Bein nach vorne geneigt wird. Vielleicht sogar mal beim Auslösen den Oberkörper bewußt zurück nehmen und über das äußere Bein gehen', 'Lehrgang Albstadt', 'Dieter Maute', 'Video - einfache Analyse', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Maximilian Keller')::uuid, 'Drehsprung', 'Arsch zu hoch und Lenker zu langsam', 'Abdruck nur aus dem Pedal und Becken nicht so hoch nehmen', 'Lehrgang Albstadt', 'Dieter Maute', 'Video - einfache Analyse', 'https://dartfi.sh/pJ4BmUhIoOd', NULL, 2, 2, 2, 1, 1),
    (md5('fbath:Hannah Schneider')::uuid, 'Handstand', 'Auf dem Rad weden Oberschenkel an den Körper rangezogen was die Aktivierung von Schulter und aufrollen Rücken blockiert.', 'Über Schulter rausschieben und Beine spreizen beginnen, dann Rücken in die senkrechte aufrollen', 'Heimtraining', 'Dieter Maute', 'Video - einfache Analyse', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'Übergang Kehrlenkersitzsteiger Kehrsteuerrohrsteiger', 'Lenker zu spät vor den rechten Oberschenkel und linkes bein zu spät vom Pedal', 'Zu Beginn direkt am Lenker ziehen und linkes Bein entlasten bzw. weg vom Pedal', 'Heimtraining', 'Dieter Maute', 'Video - einfache Analyse', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Simon Halter')::uuid, 'Drehsprung', 'Lenker dreht beim weiterspringen zuviel und zu früh mit, Schung des Körpers vor dem Rad geht wird geringer.', 'Schulter besser über dem Lenker lassen und rechte Schulter nach vorne eindrehen beim kurz machen und weiterspringen', 'Heimtraining', 'Dieter Maute', 'Video - einfache Analyse', 'https://dartfi.sh/u3DFmIOHSUc', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'Lenkerstanddrehung', 'Anfahrweg', 'Entweder Richtung Viermeterkreis auf der rechten Seite, oder am Viermeterkreis entlang anfahren', 'Heimtraining', 'Dieter Maute', 'Video - einfache Analyse', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'Drehsprung', 'Körper kommt nicht ins Schwingen vor dem Rad', 'linkes Bein über den Sattel nach außen strecken beim Rausspringen und Schulter weiter vor', 'Heimtraining', 'Dieter Maute', 'Video - einfache Analyse', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Maximilian Keller')::uuid, 'Sattellenkerstand rw.', 'Rad kippt nach innen, große Lenkbewegungen', 'immer am feinen lenken bleiben, beim aufsteigen po etwas höher und Knie weiter nach vorne schieben, sodass Körperschwerpunkt besser über dem Rad ist', 'Lehrgang Albstadt', 'Dieter Maute', 'Video - einfache Analyse', 'https://dartfi.sh/gRDnrsYgEVi', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'Lenkerstanddrehung', 'Vorderrad läuft nach außen beim Vordrehen, Oberkörper kommt nach vorne und linker Arm schlägt zurück beim Auslösen', 'Vordrehen langsam beschleunigt durchführen, Auslösen Gesamtspannung aufbauen und Arme stehen lassen, nur mit Becken und Füßen am Lenker nachdrehen', 'Heimtraining', 'Dieter Maute', 'Video - einfache Analyse', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'Übergang Kehrlenkersitz Kehrsteuerrohrsteiger', 'Zeitpunkt beim Aufkommen auf das Pedal zu spät', 'Beinbewegung kleiner machen, Lenker früher drehen, Druck aufs Pedal beim Ankommen', 'Lehrgang Albstadt', 'Lehrgangsleiter', 'Video - einfache Analyse', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Simon Halter')::uuid, 'Drehsprung', 'Vorderrad läuft quer und Rad kippt dadurch seitlich', 'Schlißen der Beine geführter sodass gefühlte Pause ensteht, kurzmachen Beine weiter um den Arm rum und klener machen, Lenker komplett mit gleich schnellem Tempo drehen, danbei Schulter besser über dem Lenker lassen', 'NK1', 'Dieter Maute', 'Video - einfache Analyse', 'https://dartfi.sh/8pyEc4kmOMl', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Simon Halter')::uuid, 'Drehsprung', 'Lenker läuft zu viel mit beim weiterspringen, Schwung vor dem Rad nicht oval sondern zu rund', 'langer warten damit Beine nicht gespreizt werden müssen, Schulter besser über dem Lenker lassen beim Weiterspringen', 'Lehrgang Albstadt', 'Dieter Maute', 'Video - einfache Analyse', 'https://dartfi.sh/PqrIzwxx1Fh', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'Steuerohrsteiger Dreh.', 'Rücken nicht gerade, trittgeschwindigkeit bleibt noch zu gering', 'Beim Vorgehen des Oberkörpers das Becken mitkippen, tritt noch schneller machen und dabei den Oberkörper schon ein wenig aufrichten.', 'Lehrgang Albstadt', 'Dieter Maute', 'Video - einfache Analyse', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'Üb Kerlenkersitzsteiger Kehrsteuerrohrsteiger', 'kommt zu spät mit linkem Fuß aufs Pedal', 'Zug am Lenker rechte Hand früher, Beinbewegung schneller und mit direktem tritt rückwärts, (Nur mit Hilfestellung, da Ablauf dann besser)', 'Lehrgang Albstadt', 'Dieter Maute', 'Video - einfache Analyse', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Maximilian Keller')::uuid, 'Kehrstandsteiger', 'Körper-Rad-Position Übergang und fahren, beim Zurückgehen Entscheidung ob vorwärts weg oder rückwärts', 'Oberkörper zu weit vorne, beim zurück gehen entweder vorwärts weg und dann im Steuerrohrsteiger wechseltritt zum runterlassen oder mehr mit dem Körper nach hinten und Rad nicht vor kippen lassen', 'Lehrgang Albstadt', 'Dieter Maute', 'Video - einfache Analyse', 'https://dartfi.sh/jhqAbIKryUb', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Maximilian Keller')::uuid, 'Übergang Kehrlenkersitzsteiger Kehrsteuerrohrsteiger', 'Ablauf alleine nicht stabil', 'Nur mit Hilfestellung machen, Oberkörper aufrecht und direkter tritt rückwärts mit linkem Fuß', 'Lehrgang Albstadt', 'Dieter Maute', 'Video - einfache Analyse', 'https://dartfi.sh/kHJXeK5RgOc', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'Lenkerstanddrehung', 'Kommt mit linkem Arm und Oberkörper beim Auslösen vor, Rad kippt nach innen', 'Beim Auslösen insgesamt mehr Spannung um Schultergürtel, dann linkes Knie nicht beugen sondern zuerst auf links Becken verlagern', 'Lehrgang Albstadt', 'Dieter Maute', 'Video - einfache Analyse', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'Übergang Kehrlenkersitzsteiger Kehrsteuerrohrsteiger', 'Becken geht nach hinten beim Bein drüber nehmen', 'Oberkörper ganz senkrecht lassen', 'NK1 Frankfurt', 'Dieter Maute', 'Video - einfache Analyse', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'Lenkerstaddrehung', '1. halbe Lenkergegenbewegung beim Vordrehen, 2. Halbe großer Armeinsatz, beide Oberkörper vorne beim Auslösen', '1. halbe gleichmäßig schneller werden beim Vordreen, 2. halbe mehr Armspannung, beide rechte Beckenseite beim Auslösen nach vorne mitnehmen.', '', 'Video - einfache Analyse', 'Ja', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'Übergang Kehrlenkersitzsteiger Standsteiger', 'Kommt im Kehrsteuerrohrsteiger zu spät aus das Pedal, Rad kippt nach hinten', 'Entweder früher linken Fuß lösen, oder Schnellere Beinbewegung und auch direkt mit Druck auf das linke Pedal, Oberkörper aufrecht lassen', '', 'Video - einfache Analyse', 'Ja', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'Drehsprung', 'Schwingt nicht', 'Rausspringen: Eindrehen und Lenker komlett drehen, linkes Bein dabei zur Seite raus; Schwingen: Schulter weiter vor und beine schliessen.', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Maximilian Keller')::uuid, 'Handstand', 'Stand nach dem Hochdrücken etwas zu gerade, Korrektur aber zuviel', 'Schon beim Hochdrücken etwas früher Schulter stehen lassen beim schließen, dann Beine und Becken in Mini-C positionieren', '', '', '', 'https://dartfi.sh/qyZR9JxADy9', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'Handstand', 'Einstieg Po hoschieben noch etwas zu wenig, Knie strecken', 'Über Schulter eintsieg Füße versuchen senkrecht 5cm hoch und dann aufrollen des Rückens, Knie strecken', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'Drehsprung', 'Körper schwingt noch zu niedrig, beim weiterdrehen stützen nicht mehr möglich', 'Eindrehen rechte Schulter und Lenker stehen lassen beim rausspringen, dann schnelle DRehbewegung des Lenkers. abanschließend Schultern deutlich weiter vor zum Schwingen und Beinde schließen und warten, beim Weiterspringen eindrehen rechte Schulter und rechtes Knie mehr um Arm über Rahmen, dann überm Lenker bleibend Lenker drehen', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'Drehsprung', 'Rausspringen linkes bein versucht nach hinten gegen Trainer Schwung zu holen, Schwingen zu flach, lenker läuft dann einfach mit und Schulter geht nach hinten', 'Beim rausspringen linkes bein zur Seite raus strecken und über Fuß nach oben außen abdrücken mit gleichzeitigem schnellen Lenkerdrehen, Schulter weiter vor und Körper schwingen lassen bis Becken links rRichtung rectem Arm kommt, dann Beine kurz machen, rechte Schullter nach vorne eindrehen und um Arm eindrehen, beim dann schnllen Drehen des Lenkers mit der Schulter über dem Lenker bleiben.', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'Lenkerhandstand', 'Schließt nach vorne', 'nach leichtem Abspringen aufrollen zu wenig, Endpsitione Schulter noch nicht eingenommen bevor Beine kontrolliert schließen', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Maximilian Keller')::uuid, 'Übergang Kehrlenkersitzsteiger Standsteiger', 'Rhythmus Pedal-Körperbewegung passt nicht, Oberkörperposition falsch', 'Oberkörper senkerht lassen, im Kehrsteuerrohrsteiger zum tritt rückwärts gleichzeitig aufstehen und Lenker nach norne schieben (nur mit Hilfestellung)', '', '', '', 'https://dartfi.sh/pc3IJcaX5f0', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'Übergang Kehrlenkersitzsteiger Standsteiger', 'Rad zu weit hinten, linker Fuß zu spät aufs Pedal', 'Oberkörper muss senkrecht bleiben, Beinbewegung kurz (nicht zur Seite), mal nur zum Kehrsteuerrohrsiger üben eventuell mit Hilfestellung bis Bewegung stabil ist und linker Fuß immer rechzeitig aufs Pedal kommt', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Maximilian Keller')::uuid, 'Übergang Kehrsteuerrohrsteiger Kehrlenkersitzsteiger', 'Bewegungsrhythmus Pedal-Körper passt nicht zusammen, Opberkörperposition', 'direkt in den Lenker sitzen zum tritt rückwärst links und Oberkörper aufrecht lassen', '', '', '', 'https://dartfi.sh/YZPe6JDgZbe', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'Lenkerhandstand', 'Scub aus Schultern und Rücken aufrollen fehlt', 'leichtes anspringen, dann schub aus Schultern und aufrollen BWS über die Senkrechte, Beine gestreckt spreizen', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'Lenkerstanddrehung', 'noch viel Armbewegung und Vordrehen etwas wenig', 'Etwas mehr Armspannung und Vordrehen insbesondere 3. etwas weiter. An sich aber hauptsächlich so weiter und effektives Auslösen erspäüren um Radlauf zu halten oder zu beschleunigen', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'Übergang Kehrlenkersitzsteiger Kehrsteuerrohrsteiger', 'linker Fuß kommt noch zu spät aufs Pedal', 'Oberkörper immer Aufrecht lassen, linker Fuß etwas früher vom Pedal und schneller drüber', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'Lenkerhandstand', 'Aufrollen noch zu wenig und ein wenig zu weit in der Schulter', 'Aufrollen bewußter machen und mehr ins Drücken übergehen, bevor Beine geschlossen werden ein wenig mehr aus Schulter rausschieben.', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'Kehrstandsteiger rw', 'Oberkörper zu weit vorne innen', 'Mehr den Oberkörper nach außen hinten bringen und Ellbogen abwinkeln', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Hannah Schneider')::uuid, 'Sattelstand', 'beim und nach dem Aufstehen Rad und Körper nicht in einer Linie', 'Vor dem lösen der Hände exakt gleichen Druck re/li Füße', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL),
