    (md5('fbath:Simon Riedinger')::uuid, 'Kehrlenkersitzsteiger Standdrehung', 'Hand geht nach vorne, Abdruck nicht synchron, Oberköerposition', 'Beim Ausholen Handverbindung stehen lassen, Abdruck synchronisieren, Oberkörper bleibt aufrecht und linke Schulter wieder zurück nehmen', 'Lehrgang Albstadt', 'Dieter Maute', 'Video - einfache Analyse', 'https://dartfi.sh/nkVpJ9XIbsg', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Charlotte Bantle')::uuid, 'Drehsprung', 'Lenker läuft mit (zu langsam)', 'Schultern weiter vor, Knie mehr in Richtung Rahmen und mit Körper um Arm rum gehen, Dann Lenker schnell drehen bevor er durch den Körper langsam mitgedreht wird.', 'Lehrgang Albstadt', 'Dieter Maute', 'Video - einfache Analyse', 'https://dartfi.sh/v1eaJbdaIB2', NULL, NULL, NULL, NULL, NULL, NULL),
