    (md5('fbath:Simon Halter')::uuid, 'Drehsprung', 'Radlauf und Drehgeschwindigkeit werden immer weniger', 'beim kurz machen mehr rechte Schulter eindrehen und um Arm gehen, Schulter beim schnellen Lenkerdrehen besser über dem Lenker lassen', 'Heimtraining', 'Dieter Maute', 'Video - einfache Analyse', 'https://dartfi.sh/cQlHpKbZsq8', NULL, NULL, NULL, NULL, NULL, NULL),
    (md5('fbath:Charlotte Bantle')::uuid, 'Drehsprung', 'Rad kippt beim reinsitzen nach innen', 'Etwas mehr um Arm und knie über Rahmen, dann Lenker schneller drehen', 'Lehrgang Albstadt', 'Dieter Maute', 'Video - einfache Analyse', 'https://dartfi.sh/xF5lHlXoNOj', NULL, NULL, NULL, NULL, NULL, NULL),
