    (md5('fbath:Hannah Reichle')::uuid, 'Sattellenkerhandstand', 'Becken wird nicht ganz drüber gerollt beim Hochdrücken, dadurch beim Schließen der Beine leichter Hüftknick', 'Am Seil abgesichert Becken ganz drüber rollen, sodass kein Drücken mehr notwendig ist, dann bewußt Beine nach oben schließen.', 'Lehrgang Albstadt', 'Dieter Maute', 'Video - einfache Analyse', 'https://dartfi.sh/bdPnkaP0gUl', NULL, NULL, NULL, NULL, NULL, NULL),
