-- =====================================================
-- Feedback-Import (Forms-Excel 2024) — gesamter Kader + alle Feedbacks
-- Idempotent: Athleten via deterministische ID + ON CONFLICT; Feedbacks
-- werden bei jedem Lauf neu gesetzt (DELETE created_by IS NULL = Importe).
-- Reine Import-/Testdaten — entfernbar. In-App erfasste Feedbacks
-- (created_by gesetzt) bleiben unberuehrt.
-- =====================================================
DO $$
DECLARE rub UUID; rubath UUID;
BEGIN
  SELECT id INTO rub FROM auth.users WHERE lower(email)='info@neue-weberei.de' LIMIT 1;
  IF rub IS NULL THEN RAISE NOTICE 'Ruben nicht gefunden, skip'; RETURN; END IF;
  SELECT a.id INTO rubath FROM athletes a WHERE a.auth_user_id=rub LIMIT 1;
  -- Kader (vom Trainer Ruben verwaltet) anlegen
  ON CONFLICT (id) DO NOTHING;
  -- Vorherige Importe entfernen (created_by IS NULL = nicht in der App erfasst)
  DELETE FROM feedback_entries WHERE created_by IS NULL;
  -- Alle Feedbacks einfuegen
  ;
END $$;
